  1	import React, { FC, useMemo, useState } from 'react';
  2	
  3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  5	import { Flex, FlexItem, SelectList, SelectOption, Text } from '@patternfly/react-core';
  6	import { InstanceTypeUnion } from '@virtualmachines/details/tabs/configuration/utils/types';
  7	
  8	import FormPFSelect from '../FormPFSelect/FormPFSelect';
  9	import TabModal from '../TabModal/TabModal';
 10	
 11	import {
 12	  getInstanceTypeFromSeriesAndSize,
 13	  getInstanceTypeSeriesAndSize,
 14	  getInstanceTypeSeriesDisplayName,
 15	  getInstanceTypesPrettyDisplaySize,
 16	  getInstanceTypesSizes,
 17	  mappedInstanceTypesToSelectOptions,
 18	} from './utils/util';
 19	
 20	type InstanceTypeModalProps = {
 21	  allInstanceTypes: InstanceTypeUnion[];
 22	  instanceType: InstanceTypeUnion;
 23	  instanceTypeVM: V1VirtualMachine;
 24	  isOpen: boolean;
 25	  onClose: () => void;
 26	  onSubmit: (
 27	    updatedVM: V1VirtualMachine,
 28	    instanceType: InstanceTypeUnion,
 29	  ) => Promise<V1VirtualMachine>;
 30	};
 31	
 32	const InstanceTypeModal: FC<InstanceTypeModalProps> = ({
 33	  allInstanceTypes,
 34	  instanceType,
 35	  instanceTypeVM,
 36	  isOpen,
 37	  onClose,
 38	  onSubmit,
 39	}) => {
 40	  const { t } = useKubevirtTranslation();
 41	  const mappedInstanceTypes = useMemo(
 42	    () => mappedInstanceTypesToSelectOptions(allInstanceTypes),
 43	    [allInstanceTypes],
 44	  );
 45	  const { series: instanceTypeSeries, size: instanceTypeSize } = useMemo(
 46	    () => getInstanceTypeSeriesAndSize(instanceType),
 47	    [instanceType],
 48	  );
 49	
 50	  const [series, setSeries] = useState<string>(
 51	    getInstanceTypeSeriesDisplayName(mappedInstanceTypes, instanceTypeSeries),
 52	  );
 53	
 54	  const [size, setSize] = useState<string>(
 55	    getInstanceTypesPrettyDisplaySize(mappedInstanceTypes, instanceTypeSeries, instanceTypeSize),
 56	  );
 57	
 58	  const handleSubmit = (selectedInstanceType: InstanceTypeUnion) =>
 59	    onSubmit(instanceTypeVM, selectedInstanceType);
 60	
 61	  return (
 62	    <TabModal
 63	      headerText={t('Edit Instancetype')}
 64	      isOpen={isOpen}
 65	      obj={getInstanceTypeFromSeriesAndSize(mappedInstanceTypes, series, size)}
 66	      onClose={onClose}
 67	      onSubmit={handleSubmit}
 68	    >
 69	      <Flex
 70	        spaceItems={{
 71	          default: 'spaceItemsXl',
 72	        }}
 73	        direction={{ default: 'column' }}
 74	        spacer={{ default: 'spacer4xl' }}
 75	      >
 76	        <FlexItem>
 77	          <Text component="h5">{t('Series')}</Text>
 78	          <FormPFSelect
 79	            onSelect={(_, value) => {
 80	              if (value !== series) {
 81	                setSeries(value as string);
 82	                setSize(null);
 83	              }
 84	            }}
 85	            selected={series}
 86	            toggleProps={{ isFullWidth: true }}
 87	          >
 88	            <SelectList>
 89	              {Object.entries(mappedInstanceTypes).map(([key, value]) => (
 90	                <SelectOption
 91	                  description={value.descriptionSeries}
 92	                  key={key}
 93	                  value={value.displayNameSeries}
 94	                >
 95	                  {value.displayNameSeries}
 96	                </SelectOption>
 97	              ))}
 98	            </SelectList>
 99	          </FormPFSelect>
100	        </FlexItem>
101	        <FlexItem>
102	          <Text component="h5">{t('Size')}</Text>
103	          <FormPFSelect
104	            onSelect={(_, value) => {
105	              setSize(value as string);
106	            }}
107	            selected={size}
108	            toggleProps={{ isFullWidth: true }}
109	          >
110	            {getInstanceTypesSizes(mappedInstanceTypes, series)?.map((item) => (
111	              <SelectOption key={item.prettyDisplaySize} value={item.prettyDisplaySize}>
112	                {item?.prettyDisplaySize}
113	              </SelectOption>
114	            ))}
115	          </FormPFSelect>
116	        </FlexItem>
117	      </Flex>
118	    </TabModal>
119	  );
120	};
121	
122	export default InstanceTypeModal;

